ValidationRule.errorConditionFormula:
AND(
    ISCHANGED( OwnerId ) ,
    OR( ISBLANK( TEXT( LeadSource ) ),
        AND( ISBLANK( NumberOfEmployees ),  
            NOT(  $Permission.Lead_Skip_No_of_Employees_Validation )
        ),
        AND( ISBLANK( Country ),
            NOT( $Permission.Lead_Skip_Country_Validation )
        ) 
    )
)
